# lib/blog/html_sanitizer.ex
defmodule Blog.HtmlSanitizer do
  @moduledoc """
  Sanitizes user-generated HTML to prevent XSS attacks
  while allowing safe formatting tags.
  """

  # Define an allowlist of safe HTML tags and attributes
  def sanitize(nil), do: ""
  def sanitize(html) when is_binary(html) do
    HtmlSanitizeEx.basic_html(html)
  end

  # For more permissive formatting (still safe):
  def sanitize_rich(nil), do: ""
  def sanitize_rich(html) when is_binary(html) do
    HtmlSanitizeEx.Scrubber.scrub(html, Blog.HtmlSanitizer.RichTextScrubber)
  end
end

# lib/blog/html_sanitizer/rich_text_scrubber.ex
defmodule Blog.HtmlSanitizer.RichTextScrubber do
  @moduledoc """
  Custom scrubber that allows rich formatting tags but strips
  all dangerous elements like <script>, <iframe>, event handlers, etc.
  """

  require HtmlSanitizeEx.Scrubber.Meta
  alias HtmlSanitizeEx.Scrubber.Meta

  # Explicitly strip dangerous tags
  Meta.strip_comments()
  Meta.remove_cdata_sections_before_scrub()

  # Allow safe text formatting tags
  Meta.allow_tag_with_these_attributes("p", ["class"])
  Meta.allow_tag_with_these_attributes("br", [])
  Meta.allow_tag_with_these_attributes("strong", [])
  Meta.allow_tag_with_these_attributes("b", [])
  Meta.allow_tag_with_these_attributes("em", [])
  Meta.allow_tag_with_these_attributes("i", [])
  Meta.allow_tag_with_these_attributes("u", [])
  Meta.allow_tag_with_these_attributes("s", [])
  Meta.allow_tag_with_these_attributes("blockquote", ["class"])
  Meta.allow_tag_with_these_attributes("code", ["class"])
  Meta.allow_tag_with_these_attributes("pre", ["class"])
  Meta.allow_tag_with_these_attributes("h1", ["class"])
  Meta.allow_tag_with_these_attributes("h2", ["class"])
  Meta.allow_tag_with_these_attributes("h3", ["class"])
  Meta.allow_tag_with_these_attributes("h4", ["class"])
  Meta.allow_tag_with_these_attributes("ul", ["class"])
  Meta.allow_tag_with_these_attributes("ol", ["class"])
  Meta.allow_tag_with_these_attributes("li", ["class"])
  Meta.allow_tag_with_these_attributes("span", ["class"])
  Meta.allow_tag_with_these_attributes("div", ["class"])
  Meta.allow_tag_with_these_attributes("table", ["class"])
  Meta.allow_tag_with_these_attributes("thead", [])
  Meta.allow_tag_with_these_attributes("tbody", [])
  Meta.allow_tag_with_these_attributes("tr", [])
  Meta.allow_tag_with_these_attributes("th", ["class"])
  Meta.allow_tag_with_these_attributes("td", ["class"])

  # Allow links but only with safe protocols
  Meta.allow_tag_with_uri_attributes("a", ["href"], ["http", "https", "mailto"])
  Meta.allow_tag_with_these_attributes("a", ["title", "class", "rel", "target"])

  # Allow images but only with safe protocols
  Meta.allow_tag_with_uri_attributes("img", ["src"], ["http", "https"])
  Meta.allow_tag_with_these_attributes("img", ["alt", "title", "class", "width", "height"])

  # Strip everything else
  Meta.strip_everything_not_covered()
end

# lib/blog_web/helpers/sanitize_helpers.ex
defmodule BlogWeb.SanitizeHelpers do
  @moduledoc """
  Template helpers for rendering sanitized user HTML content.
  """

  def sanitized_raw(html) do
    html
    |> Blog.HtmlSanitizer.sanitize_rich()
    |> Phoenix.HTML.raw()
  end
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  alias Blog.Posts
  import BlogWeb.SanitizeHelpers

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)

    {:ok, assign(socket, post: post, page_title: post.title)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto px-4 py-8">
      <article class="blog-post">
        <header class="mb-8">
          <h1 class="text-4xl font-bold text-gray-900 mb-2"><%= @post.title %></h1>
          <div class="text-gray-500 text-sm">
            <span>By <%= @post.author.name %></span>
            <span class="mx-2">·</span>
            <time datetime={@post.published_at}><%= format_date(@post.published_at) %></time>
          </div>
        </header>

        <div class="prose prose-lg max-w-none">
          <%!--
            SECURITY: Never use raw(@post.content) directly with user input!
            Always sanitize first to prevent XSS attacks.
            sanitized_raw/1 strips dangerous tags like <script>, <iframe>,
            event handlers (onclick, onerror, etc.), and javascript: URIs
            while preserving safe formatting HTML.
          --%>
          <%= sanitized_raw(@post.content) %>
        </div>
      </article>

      <div class="mt-12 pt-8 border-t border-gray-200">
        <.link navigate={~p"/posts"} class="text-blue-600 hover:text-blue-800">
          ← Back to all posts
        </.link>
      </div>
    </div>
    """
  end

  defp format_date(nil), do: ""
  defp format_date(datetime) do
    Calendar.strftime(datetime, "%B %d, %Y")
  end
end

# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  alias Blog.Posts
  import BlogWeb.SanitizeHelpers

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_published_posts()
    {:ok, assign(socket, posts: posts, page_title: "Blog")}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto px-4 py-8">
      <h1 class="text-3xl font-bold mb-8">Blog Posts</h1>

      <div class="space-y-8">
        <article :for={post <- @posts} class="border-b border-gray-200 pb-8">
          <h2 class="text-2xl font-semibold mb-2">
            <.link navigate={~p"/posts/#{post.id}"} class="text-gray-900 hover:text-blue-600">
              <%= post.title %>
            </.link>
          </h2>
          <div class="text-gray-500 text-sm mb-4">
            <span>By <%= post.author.name %></span>
            <span class="mx-2">·</span>
            <time datetime={post.published_at}><%= format_date(post.published_at) %></time>
          </div>
          <div class="prose max-w-none text-gray-700">
            <%!-- Sanitize excerpt/preview content too --%>
            <%= sanitized_raw(truncate_html(post.content, 300)) %>
          </div>
        </article>
      </div>
    </div>
    """
  end

  defp format_date(nil), do: ""
  defp format_date(datetime) do
    Calendar.strftime(datetime, "%B %d, %Y")
  end

  defp truncate_html(nil, _), do: ""
  defp truncate_html(html, max_length) do
    # Strip HTML for excerpt, then truncate safely
    text = HtmlSanitizeEx.strip_tags(html)
    if String.length(text) > max_length do
      String.slice(text, 0, max_length) <> "..."
    else
      text
    end
  end
end

# lib/blog/posts.ex
defmodule Blog.Posts do
  alias Blog.Repo
  alias Blog.Posts.Post
  import Ecto.Query

  def list_published_posts do
    Post
    |> where([p], not is_nil(p.published_at))
    |> order_by([p], desc: p.published_at)
    |> preload(:author)
    |> Repo.all()
  end

  def get_post!(id) do
    Post
    |> preload(:author)
    |> Repo.get!(id)
  end

  @doc """
  Creates a post, sanitizing the HTML content before storage.
  Defense in depth: sanitize on write AND on read.
  """
  def create_post(attrs) do
    attrs = sanitize_content_attrs(attrs)

    %Post{}
    |> Post.changeset(attrs)
    |> Repo.insert()
  end

  def update_post(%Post{} = post, attrs) do
    attrs = sanitize_content_attrs(attrs)

    post
    |> Post.changeset(attrs)
    |> Repo.update()
  end

  defp sanitize_content_attrs(%{"content" => content} = attrs) do
    %{attrs | "content" => Blog.HtmlSanitizer.sanitize_rich(content)}
  end

  defp sanitize_content_attrs(%{content: content} = attrs) do
    %{attrs | content: Blog.HtmlSanitizer.sanitize_rich(content)}
  end

  defp sanitize_content_attrs(attrs), do: attrs
end

# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :title, :string
    field :content, :string
    field :published_at, :utc_datetime

    belongs_to :author, Blog.Accounts.User

    timestamps()
  end

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content, :published_at, :author_id])
    |> validate_required([:title, :content, :author_id])
    |> validate_length(:title, max: 255)
    |> foreign_key_constraint(:author_id)
  end
end

# lib/blog_web/router.ex (relevant routes)
defmodule BlogWeb.Router do
  use BlogWeb, :router

  pipeline :browser do
    plug :accepts, ["html"]
    plug :fetch_session
    plug :fetch_live_flash
    plug :put_root_layout, html: {BlogWeb.Layouts, :root}
    plug :protect_from_forgery
    plug :put_secure_headers, %{"content-security-policy" => "default-src 'self'; img-src 'self' https:; style-src 'self' 'unsafe-inline'"}
  end

  scope "/", BlogWeb do
    pipe_through :browser

    live "/posts", PostLive.Index, :index
    live "/posts/:id", PostLive.Show, :show
  end
end

# test/blog/html_sanitizer_test.exs
defmodule Blog.HtmlSanitizerTest do
  use ExUnit.Case, async: true

  alias Blog.HtmlSanitizer

  describe "sanitize_rich/1" do
    test "allows safe formatting tags" do
      html = "<p><strong>Bold</strong> and <em>italic</em></p>"
      assert HtmlSanitizer.sanitize_rich(html) == html
    end

    test "strips script tags" do
      html = "<p>Hello</p><script>alert('xss')</script>"
      result = HtmlSanitizer.sanitize_rich(html)
      refute result =~ "<script>"
      refute result =~ "alert"
      assert result =~ "<p>Hello</p>"
    end

    test "strips event handler attributes" do
      html = ~s(<p onclick="alert('xss')">Click me</p>)
      result = HtmlSanitizer.sanitize_rich(html)
      refute result =~ "onclick"
      assert result =~ "<p>Click me</p>"
    end

    test "strips javascript: URIs" do
      html = ~s(<a href="javascript:alert('xss')">Click</a>)
      result = HtmlSanitizer.sanitize_rich(html)
      refute result =~ "javascript:"
    end

    test "strips iframe tags" do
      html = ~s(<iframe src="https://evil.com"></iframe><p>Safe</p>)
      result = HtmlSanitizer.sanitize_rich(html)
      refute result =~ "<iframe"
      assert result =~ "<p>Safe</p>"
    end

    test "allows safe links" do
      html = ~s(<a href="https://example.com" title="Example">Link</a>)
      result = HtmlSanitizer.sanitize_rich(html)
      assert result =~ ~s(href="https://example.com")
    end

    test "allows safe images" do
      html = ~s(<img src="https://example.com/img.png" alt="Photo">)
      result = HtmlSanitizer.sanitize_rich(html)
      assert result =~ ~s(src="https://example.com/img.png")
    end

    test "handles nil input" do
      assert HtmlSanitizer.sanitize_rich(nil) == ""
    end

    test "strips onerror on img tags" do
      html = ~s(<img src="x" onerror="alert('xss')">)
      result = HtmlSanitizer.sanitize_rich(html)
      refute result =~ "onerror"
    end
  end
end